import{_ as i,o as e,c as a,a2 as t}from"./chunks/framework.CKCxdkvf.js";const c=JSON.parse('{"title":"RFC-003 — Lambert worker: message protocol, progress reporting, cancellation","description":"","frontmatter":{},"headers":[],"relativePath":"rfc/RFC-003.md","filePath":"rfc/RFC-003.md"}'),o={name:"rfc/RFC-003.md"};function r(n,s,l,h,p,d){return e(),a("div",null,[...s[0]||(s[0]=[t('<h1 id="rfc-003-—-lambert-worker-message-protocol-progress-reporting-cancellation" tabindex="-1">RFC-003 — Lambert worker: message protocol, progress reporting, cancellation <a class="header-anchor" href="#rfc-003-—-lambert-worker-message-protocol-progress-reporting-cancellation" aria-label="Permalink to &quot;RFC-003 — Lambert worker: message protocol, progress reporting, cancellation&quot;">​</a></h1><blockquote><p>Status · Decided TA anchor · §components/lambert-worker · §contracts/lambert-worker-message Closed by · ADR-022 (2026-04-28) Why this is an RFC · ADR-008 locks the Lambert solver in a Web Worker. The message protocol, progress reporting strategy, and cancellation mechanism have genuine alternatives with different complexity and UX implications.</p></blockquote><h2 id="the-question" tabindex="-1">The question <a class="header-anchor" href="#the-question" aria-label="Permalink to &quot;The question&quot;">​</a></h2><p>The Lambert solver computes 11,200 cells (~200ms fast, 1-3s slow hardware). Open questions: does the user see progress during computation? If the user changes the date range mid-computation, does the old computation get cancelled cleanly? What&#39;s the exact message shape?</p><h2 id="use-cases" tabindex="-1">Use cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to &quot;Use cases&quot;">​</a></h2><ul><li>User opens plan screen: porkchop plot computes for default date range</li><li>User changes departure slider mid-computation: new computation should supersede old one</li><li>Slow device: user should see feedback, not a frozen UI</li></ul><h2 id="goals" tabindex="-1">Goals <a class="header-anchor" href="#goals" aria-label="Permalink to &quot;Goals&quot;">​</a></h2><ul><li>Main thread stays responsive (ADR-008 guarantees this)</li><li>Stale results never overwrite fresh ones</li><li>Progress feedback on slow devices</li><li>Protocol simple enough that the worker code is readable</li></ul><h2 id="constraints" tabindex="-1">Constraints <a class="header-anchor" href="#constraints" aria-label="Permalink to &quot;Constraints&quot;">​</a></h2><p>Web Workers communicate via <code>postMessage</code>. No SharedArrayBuffer required. Worker must be a separate file importable by Vite.</p><h2 id="proposed-approach" tabindex="-1">Proposed approach <a class="header-anchor" href="#proposed-approach" aria-label="Permalink to &quot;Proposed approach&quot;">​</a></h2><p><strong>Protocol:</strong></p><p>Main → Worker:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{ </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;depRange&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">depStart</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">depEnd</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">], </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;arrRange&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">arrStart</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">arrEnd</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">], </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;steps&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">112</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">100</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] }</span></span></code></pre></div><p>Worker → Main (progress, every 10 rows):</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{ </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;progress&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.45</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span></code></pre></div><p>Worker → Main (result):</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{ </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;grid&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [[</span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">dv</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">...</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">], </span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">...</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">], </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;depDays&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">...</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">], </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;arrDays&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">...</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] }</span></span></code></pre></div><p><strong>Cancellation:</strong> monotonically increasing <code>id</code>. The worker checks current <code>id</code> before posting any message — if it has changed, discard. Simpler than <code>terminate()</code>/<code>new Worker()</code>.</p><p><strong>Progress:</strong> post every 10 rows. The plan screen shows a progress bar that fills over the computation time.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><p><strong>No cancellation</strong> — stale results overwrite fresh ones if the user changes inputs quickly. Real bug. Rejected.</p><p><strong><code>terminate()</code> + <code>new Worker()</code></strong> — clean slate; ~10ms worker startup cost. More complex lifecycle. The <code>id</code>-based approach is equivalent and simpler.</p><p><strong>Streaming (post each row as computed)</strong> — allows partial porkchop rendering; more complex render code; not needed at target computation time.</p><h2 id="trade-offs" tabindex="-1">Trade-offs <a class="header-anchor" href="#trade-offs" aria-label="Permalink to &quot;Trade-offs&quot;">​</a></h2><p>The <code>id</code> field adds minor complexity to every message. The alternative (stale results) is a real UX bug.</p><h2 id="open-questions" tabindex="-1">Open questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open questions&quot;">​</a></h2><ol><li>Should <code>steps</code> be configurable from the UI, or fixed at [112, 100]?</li><li>Progress interval: every 10 rows, every 1%, or time-based (every 100ms)?</li><li>Should the worker be kept alive between plan screen visits, or terminated on navigation?</li></ol><h2 id="closing-evidence" tabindex="-1">Closing evidence <a class="header-anchor" href="#closing-evidence" aria-label="Permalink to &quot;Closing evidence&quot;">​</a></h2><p>Worker running in production with porkchop plot. Input changes cancel previous computation. Available at Slice 3 gate.</p><h2 id="how-this-closes" tabindex="-1">How this closes <a class="header-anchor" href="#how-this-closes" aria-label="Permalink to &quot;How this closes&quot;">​</a></h2><p>One ADR: Lambert worker message protocol and cancellation strategy.</p>',32)])])}const g=i(o,[["render",r]]);export{c as __pageData,g as default};
